#include <hexi/dynamic_buffer.h>
#include <vector>
#include <cstdint>

template<size_t block_size = 1024>
std::vector<uint8_t> peek_data_from_buffer(const hexi::dynamic_buffer<block_size>& buffer, size_t bytes_to_peek) {
    // Create a destination buffer with the specified size
    std::vector<uint8_t> destination(bytes_to_peek);

    // Use the buffer's copy method to copy data without advancing read cursor
    buffer.copy(destination.data(), bytes_to_peek);

    // Return the copied data
    return destination;
}
```

