    PoolObject() : id(0), value(0.0) {}

    PoolObject(int i, double v) : id(i), value(v) {}
};

std::vector<PoolObject*> create_object_pool(hexi::block_allocator<PoolObject, 10>& allocator) {
    // Create an array of three PoolObject objects with different values
    PoolObject obj1(1, 1.0);
    PoolObject obj2(2, 2.0);
    PoolObject obj3(3, 3.0);

    // Use the allocator's allocate method to allocate 3 PoolObject instances
    // Pass an array of three PoolObject objects with different values
    PoolObject* allocated_objs[3];
    allocated_objs[0] = allocator.allocate(obj1.id, obj1.value);
    allocated_objs[1] = allocator.allocate(obj2.id, obj2.value);
    allocated_objs[2] = allocator.allocate(obj3.id, obj3.value);

    // Store the returned pointers in a vector and return the vector
    std::vector<PoolObject*> result;
    for (int i = 0; i < 3; ++i) {
        result.push_back(allocated_objs[i]);
    }

    return result;
}

